export class InventoryError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'InventoryError';
  }
}

interface Reservation {
  sku: string;
  qty: number;
  timer?: ReturnType<typeof setTimeout>;
}

interface Inventory {
  setStock(sku: string, qty: number): void;
  getAvailable(sku: string): number;
  reserve(sku: string, qty: number, ttlMs?: number): string;
  release(id: string): void;
  confirm(id: string): void;
}

export function createInventory(): Inventory {
  const stock = new Map<string, number>();
  const reservations = new Map<string, Reservation>();
  let nextId = 0;

  function getReserved(sku: string): number {
    let total = 0;
    for (const r of reservations.values()) {
      if (r.sku === sku) total += r.qty;
    }
    return total;
  }

  return {
    setStock(sku: string, qty: number): void {
      stock.set(sku, qty);
    },

    getAvailable(sku: string): number {
      const total = stock.get(sku) ?? 0;
      return total - getReserved(sku);
    },

    reserve(sku: string, qty: number, ttlMs?: number): string {
      if (qty < 0) {
        throw new InventoryError(`Cannot reserve negative quantity: ${qty}`);
      }
      const available = this.getAvailable(sku);
      if (qty > available) {
        throw new InventoryError(
          `Insufficient stock for SKU "${sku}": requested ${qty}, available ${available}`
        );
      }

      const id = String(++nextId);
      const reservation: Reservation = { sku, qty };

      if (ttlMs !== undefined) {
        reservation.timer = setTimeout(() => {
          reservations.delete(id);
        }, ttlMs);
      }

      reservations.set(id, reservation);
      return id;
    },

    release(id: string): void {
      const reservation = reservations.get(id);
      if (!reservation) return;
      if (reservation.timer !== undefined) {
        clearTimeout(reservation.timer);
      }
      reservations.delete(id);
    },

    confirm(id: string): void {
      const reservation = reservations.get(id);
      if (!reservation) return;
      if (reservation.timer !== undefined) {
        clearTimeout(reservation.timer);
      }
      // Reduce total stock permanently by the reserved amount
      const current = stock.get(reservation.sku) ?? 0;
      stock.set(reservation.sku, current - reservation.qty);
      reservations.delete(id);
    },
  };
}

